tbl &lt;-
  starwars %&gt;%
  select(name, height, mass, homeworld)

tbl %&gt;%
  filter(! is.na(mass) & ! is.na(height)) %&gt;%
  mutate(bmi = mass / (height/100)^2) %&gt;%
  group_by(homeworld) %&gt;%
  summarise(
    count = n(),
    avg_height = mean(height),
    avg_mass = mean(mass),
    avg_bmi = mean(bmi)
  ) %&gt;%
  arrange(desc(avg_bmi))

